import React from 'react';
import { useWebSocket } from './hooks/useWebSocket';
import DashboardOverview from './components/DashboardOverview';
import QueryAnalytics from './components/QueryAnalytics';
import ProductionScore from './components/ProductionScore';
import { AgentRegistry } from './components/AgentRegistry';
import { SystemTerminal } from './components/SystemTerminal';

function App() {
    const { data, isConnected } = useWebSocket('ws://localhost:8000/ws');

    return (
        <div className="bg-black text-slate-100 font-display min-h-screen flex flex-col overflow-x-hidden selection:bg-[#ff382e] selection:text-white">
            {/* Header */}
            <header className="flex items-center justify-between whitespace-nowrap border-b border-[#2A2A2A] px-8 py-4 bg-black sticky top-0 z-50">
                <div className="flex items-center gap-4">
                    <div className="size-6 text-white flex items-center justify-center border border-white rounded-sm p-1">
                        <svg fill="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                            <path d="M12 2L2 22h20L12 2zm0 4.3l6.5 13H5.5L12 6.3z"></path>
                        </svg>
                    </div>
                    <h1 className="text-white text-xl font-bold leading-tight tracking-widest dot-matrix-text uppercase">APEX.NEXUS</h1>
                </div>
                <div className="flex gap-4 font-mono">
                    <div className="flex items-center gap-2 px-4 py-2 rounded-lg border border-[#2A2A2A] bg-[#111]">
                        <span className="text-slate-400 text-xs uppercase">SYSTEM_TIME:</span>
                        <span className="text-white text-sm font-bold">
                            {new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                        </span>
                    </div>
                    <div className="flex items-center gap-3 px-4 py-2 rounded-lg border border-[#2A2A2A] bg-[#111]">
                        <span className="text-slate-400 text-xs uppercase">TELEMETRY:</span>
                        <span className="text-white text-sm font-bold uppercase">{isConnected ? 'ONLINE' : 'OFFLINE'}</span>
                        <span className="relative flex h-2 w-2">
                            <span className={`animate-ping absolute inline-flex h-full w-full rounded-full ${isConnected ? 'bg-white' : 'bg-red-500'} opacity-75`}></span>
                            <span className={`relative inline-flex rounded-full h-2 w-2 ${isConnected ? 'bg-white' : 'bg-red-500'}`}></span>
                        </span>
                    </div>
                </div>
            </header>

            {/* Main Content */}
            <main className="flex-1 p-8 grid grid-cols-1 lg:grid-cols-4 gap-6">
                {/* Left Column: KPIs & Analytics (3/4th width) */}
                <div className="lg:col-span-3 flex flex-col gap-6">
                    <DashboardOverview />
                    <div className="glass-panel rounded-xl p-6 flex-1 flex flex-col min-h-[400px]">
                        <QueryAnalytics data={data} />
                    </div>
                </div>

                {/* Right Column: Agent Registry */}
                <div className="flex flex-col gap-6">
                    <div className="glass-panel rounded-xl flex flex-col h-full min-h-[500px]">
                        <div className="p-4 border-b border-[#2A2A2A] flex justify-between items-center bg-[#0a0a0a] rounded-t-xl">
                            <h3 className="text-slate-300 text-xs font-mono tracking-wider uppercase">AGENT_REGISTRY</h3>
                            <span className="text-xs font-mono text-slate-500 uppercase">TOTAL: 4</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-2">
                            <AgentRegistry />
                        </div>
                    </div>
                </div>
            </main>

            {/* Footer Ticker */}
            <SystemTerminal logs={data?.alerts} />
        </div>
    );
}

export default App;
